    <style>
      .option-panel-container {
        width: 100%;
        max-width: 85%;
        margin: 10px auto;
        border-radius: 18px;
        background: #FFF9FA; /* 和思维链一样的樱花白背景 */
        backdrop-filter: blur(12px);
        -webkit-backdrop-filter: blur(12px);
        border: 1.5px solid #FBCFE8; /* 粉色边框 */
        box-shadow: 
          0 8px 20px rgba(244, 114, 182, 0.15),
          0 2px 8px rgba(249, 168, 212, 0.10);
        font-family: 'M PLUS Rounded 1c', -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
        color: #6D5B79; /* 深紫罗兰文字 */
        overflow: hidden;
        transition: box-shadow 0.3s ease, transform 0.3s ease;
      }

      .option-panel-container:hover {
        transform: translateY(-2px);
        box-shadow: 
          0 12px 28px rgba(244, 114, 182, 0.20),
          0 4px 12px rgba(249, 168, 212, 0.15);
      }

      .option-panel-header {
        padding: 14px 18px;
        font-size: 0.98em;
        font-weight: 700;
        background: #FEEFF4; /* 草莓牛奶色 */
        border-bottom: 1.5px solid #FBCFE8;
        text-align: center;
        letter-spacing: 0.5px;
        color: #584964;
        position: relative;
      }

      /* 可爱的装饰线 */
      .option-panel-header::after {
        content: '';
        display: block;
        width: 50px;
        height: 2px;
        margin: 8px auto 0;
        background: linear-gradient(90deg, #F472B6, #F9A8D4, #FBCFE8);
        border-radius: 2px;
        opacity: 0.7;
      }

      /* 标题两侧的小星星装饰 */
      .option-panel-header::before {
        content: '✨';
        position: absolute;
        left: 12px;
        top: 50%;
        transform: translateY(-50%);
        font-size: 1.2em;
        animation: twinkle 2s ease-in-out infinite;
      }

      @keyframes twinkle {
        0%, 100% { opacity: 1; transform: translateY(-50%) scale(1); }
        50% { opacity: 0.6; transform: translateY(-50%) scale(0.9); }
      }

      .option-list {
        list-style: none;
        padding: 14px 16px;
        margin: 0;
        display: grid;
        gap: 10px;
      }

      .option-item {
        background: rgba(254, 239, 244, 0.5); /* 浅粉色背景 */
        border-radius: 12px;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        border: 1.5px solid rgba(251, 207, 232, 0.4);
        position: relative;
        overflow: hidden;
      }

      /* 左侧彩色条 */
      .option-item::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 3px;
        height: 100%;
        background: var(--accent);
        opacity: 0;
        transition: opacity 0.3s ease;
        border-radius: 12px 0 0 12px;
      }

      .option-item:hover {
        background: rgba(254, 239, 244, 0.8);
        transform: translateX(6px) scale(1.02);
        border-color: var(--accent);
        box-shadow: 0 4px 12px rgba(244, 114, 182, 0.15);
      }

      .option-item:hover::before {
        opacity: 1;
      }

      .option-link {
        display: flex;
        align-items: center;
        padding: 12px 16px;
        text-decoration: none;
        color: #6D5B79;
        font-size: 0.92em;
        font-weight: 500;
        cursor: pointer;
        position: relative;
        z-index: 1;
      }

      .option-icon {
        margin-right: 12px;
        font-size: 1.3em;
        min-width: 24px;
        text-align: center;
        transition: transform 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);
        filter: brightness(1.1);
      }

      .option-item:hover .option-icon {
        transform: scale(1.2) rotate(5deg);
      }

      /* 为每个选项定制颜色 */
      .option-item:nth-child(1) {
        --accent: #F472B6; /* 主粉色 */
      }

      .option-item:nth-child(2) {
        --accent: #F9A8D4; /* 淡粉色 */
      }

      .option-item:nth-child(3) {
        --accent: #FBCFE8; /* 樱花粉 */
      }

      .option-item:nth-child(4) {
        --accent: #E879F9; /* 紫粉色 */
      }

      /* 点击时的反馈效果 */
      .option-item:active {
        transform: translateX(6px) scale(0.98);
      }

      @media (max-width: 480px) {
        .option-panel-container {
          max-width: 95%;
