    <script>
      const triggerQuickReply = (text) => {
        if (!text || text.trim() === "") {
          console.warn("Attempted to send an empty message.");
          return;
        }

        // 检查SillyTavern环境并将文本附加到输入框
        try {
            // 寻找父窗口的 #send_textarea 输入框
            const input = window.parent.document.querySelector('#send_textarea'); 
            if (input) {
                const currentValue = input.value.trim();
                // 将文本附加到输入框，如果已有内容则换行
                input.value = currentValue ? `${currentValue}\n${text}` : text;
                // 触发input事件，以便SillyTavern识别更改
                input.dispatchEvent(new Event('input', { bubbles: true }));
            } else {
                console.error('SillyTavern input #send_textarea not found.');
            }
        } catch (error) {
            console.error('Error appending text to #send_textarea:', error);
             // 捕获跨域等错误时，在控制台打印信息
            console.log("Error accessing parent input. Mock append:", text);
        }
      };

      const handleOptionClick = (event) => {
        const link = event.target.closest(".option-link");
        if (!link) {
          return;
        }

        const fullText = link.dataset.optionText;

        if (typeof fullText !== "string") {
          console.error(
            "Clicked link is missing 'data-option-text' attribute.",
            link
          );
          return;
        }

        const optionText =
          fullText.startsWith("[") && fullText.endsWith("]")
            ? fullText.slice(1, -1)
            : fullText;

        console.info("触发文本", { fullText, optionText });

        triggerQuickReply(optionText);
      };

      const initializeEventListeners = () => {
        const optionList = document.getElementById("izumi-option-list");

        if (optionList) {
          optionList.addEventListener("click", handleOptionClick);
        } else {
          console.warn(
            "Element with ID 'izumi-option-list' not found. No listener attached."
          );
        }
      };

      document.addEventListener("DOMContentLoaded", initializeEventListeners);
    </script>
